import * as React from 'react';
import { useOverflowContext } from '../overflow/hooks';
import { createContextHook } from '@universe-design/react-utilities';

export const useTab = (props: { key: string }) => {
  const { key } = props;
  const { omittedKeys } = useOverflowContext();
  return React.useMemo(
    () => ({
      key,
      isOmitted: omittedKeys.includes(key),
    }),
    [key, omittedKeys],
  );
};

type TabContextType = ReturnType<typeof useTab>;

export const { useContext: useTabContext, Provider: TabContextProvider } = createContextHook<TabContextType>(
  'TabContext',
  {
    strict: true,
  },
);

export const TabProvider: React.FC<{ tabKey: string }> = ({ tabKey, children }) => (
  <TabContextProvider value={useTab({ key: tabKey })}>{children}</TabContextProvider>
);
